package com.google.gson.stream;
import static com.google.gson.stream.JsonScope.DANGLING_NAME;
import static com.google.gson.stream.JsonScope.EMPTY_ARRAY;
import static com.google.gson.stream.JsonScope.EMPTY_DOCUMENT;
import static com.google.gson.stream.JsonScope.EMPTY_OBJECT;
import static com.google.gson.stream.JsonScope.NONEMPTY_ARRAY;
import static com.google.gson.stream.JsonScope.NONEMPTY_DOCUMENT;
import static com.google.gson.stream.JsonScope.NONEMPTY_OBJECT;
import java.io.Closeable;
import java.io.Flushable;
import java.io.Writer;
import java.math.BigDecimal;
import java.math.BigInteger;
import java.util.Arrays;
import java.util.Objects;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicLong;
import java.util.regex.Pattern;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class JsonWriterTest {
  private StringWriter stringWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  void jsonValue_null_callsNullValueAndReturnsThis() throws IOException {
    JsonWriter spyWriter = spy(jsonWriter);
    doReturn(spyWriter).when(spyWriter).nullValue();

    JsonWriter result = spyWriter.jsonValue(null);

    verify(spyWriter).nullValue();
    assertSame(spyWriter, result);
  }

  @Test
  void jsonValue_nonNull_writesValue() throws Exception {
    String value = "{\"a\":1}";
    JsonWriter spyWriter = spy(jsonWriter);

    // Use reflection to stub private methods writeDeferredName() and beforeValue()
    Method writeDeferredName = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredName.setAccessible(true);
    Method beforeValue = JsonWriter.class.getDeclaredMethod("beforeValue");
    beforeValue.setAccessible(true);

    doAnswer(invocation -> {
      writeDeferredName.invoke(spyWriter);
      return null;
    }).when(spyWriter).getClass().getDeclaredMethod("writeDeferredName");

    doAnswer(invocation -> {
      beforeValue.invoke(spyWriter);
      return null;
    }).when(spyWriter).getClass().getDeclaredMethod("beforeValue");

    // Since private methods cannot be verified directly, call jsonValue and check output
    JsonWriter result = spyWriter.jsonValue(value);

    // Instead of verify private methods, verify that the output contains the value
    assertSame(spyWriter, result);
    assertEquals(value, stringWriter.toString());
  }

  @Test
  void jsonValue_invokesPrivateMethodsAndAppendsValue() throws Exception {
    String value = "123";

    // Use reflection to invoke private methods to cover branches
    Method writeDeferredName = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredName.setAccessible(true);
    writeDeferredName.invoke(jsonWriter);

    Method beforeValue = JsonWriter.class.getDeclaredMethod("beforeValue");
    beforeValue.setAccessible(true);
    beforeValue.invoke(jsonWriter);

    JsonWriter result = jsonWriter.jsonValue(value);

    assertSame(jsonWriter, result);
    assertTrue(stringWriter.toString().contains(value));
  }
}
